import json
from lambda_utils import fetch_from_origin, get_request_body
from urllib.parse import urlparse, parse_qs
import requests

def lambda_handler(event, context):
    if event['headers'] and 'X-Enrich-URL' in event['headers']:
        enrich_url = event['headers']['X-Enrich-URL']
        
        try:
            response = requests.get(enrich_url)
            
            if response.status_code == 200:
                enrichment_data = json.loads(response.text)
                
                # Modify the request to include the enriched data
                new_request_body = get_request_body(event, context)
                new_request_body['X-Enrichment'] = enrichment_data
                
                # Forward the modified request to the origin
                fetch_from_origin(new_request_body, event, context)
            else:
                print(f"Failed to retrieve enrichment data: {response.text}")
        except Exception as e:
            print(f"Error fetching enrichment data: {str(e)}")
    
    # If no enrich URL is specified in headers or fails to fetch, forward request to origin
    fetch_from_origin(get_request_body(event, context), event, context)